package com.enterprise.banking.service;

import org.apache.cxf.annotations.EndpointProperties;
import org.apache.cxf.annotations.EndpointProperty;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.jws.WebService;
import java.math.BigDecimal;
import java.time.Instant;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.regex.Pattern;

@WebService(
        endpointInterface = "com.enterprise.banking.service.BankingService",
        serviceName = "BankingService",
        portName = "BankingServicePort",
        targetNamespace = "https://enterprise.com/banking",
        wsdlLocation = "WEB-INF/wsdl/BankingService.wsdl"
)
@EndpointProperties({
        @EndpointProperty(key = "ws-security.signature.properties", value = "server-crypto.properties"),
        @EndpointProperty(key = "ws-security.encryption.properties", value = "server-crypto.properties"),
        @EndpointProperty(key = "ws-security.callback-handler", value = "com.enterprise.banking.security.ServerPasswordCallback"),
        @EndpointProperty(key = "ws-security.signature.username", value = "bankserver"),
        @EndpointProperty(key = "ws-security.encryption.username", value = "useReqSigCert"),
        @EndpointProperty(key = "ws-security.is-bsp-compliant", value = "true"),
        @EndpointProperty(key = "ws-security.timestamp.timeToLive", value = "300"),
        @EndpointProperty(key = "ws-security.timestamp.futureTimeToLive", value = "60")
})
public class BankingServiceImpl implements BankingService {

    private static final Logger LOG = LoggerFactory.getLogger(BankingServiceImpl.class);

    private static final Pattern ACCOUNT_ID_PATTERN = Pattern.compile("^[A-Z]{2}\\d{2}[A-Z0-9]{4}\\d{7}([A-Z0-9]?){0,16}$");
    private static final Pattern CURRENCY_PATTERN = Pattern.compile("^[A-Z]{3}$");
    private static final Pattern REFERENCE_PATTERN = Pattern.compile("^[A-Za-z0-9\\-]{1,64}$");
    private static final BigDecimal MAX_TRANSFER_AMOUNT = new BigDecimal("1000000.00");
    private static final BigDecimal MIN_TRANSFER_AMOUNT = new BigDecimal("0.01");
    private static final Set<String> ALLOWED_CURRENCIES = Set.of("USD", "EUR", "GBP", "CHF", "JPY");

    // In production, use a proper database
    private final ConcurrentHashMap<String, BigDecimal> accountBalances = new ConcurrentHashMap<>();
    private final ConcurrentHashMap<String, List<TransactionRecord>> transactionHistory = new ConcurrentHashMap<>();
    private final Set<String> processedReferences = ConcurrentHashMap.newKeySet();

    public BankingServiceImpl() {
        // Demo data
        accountBalances.put("GB29NWBK6016131926819", new BigDecimal("50000.00"));
        accountBalances.put("DE89370400440532013000", new BigDecimal("75000.00"));
        transactionHistory.put("GB29NWBK6016131926819", Collections.synchronizedList(new ArrayList<>()));
        transactionHistory.put("DE89370400440532013000", Collections.synchronizedList(new ArrayList<>()));
    }

    @Override
    public TransferResponse transfer(TransferRequest request) {
        TransferResponse response = new TransferResponse();
        response.setTimestamp(Instant.now().toString());

        try {
            validateTransferRequest(request);

            // Idempotency check
            if (!processedReferences.add(request.getTransactionReference())) {
                response.setStatus("DUPLICATE");
                response.setMessage("Transaction reference already processed");
                response.setTransactionId("N/A");
                LOG.warn("Duplicate transaction reference: {}", sanitizeLogInput(request.getTransactionReference()));
                return response;
            }

            BigDecimal sourceBalance = accountBalances.get(request.getSourceAccountId());
            BigDecimal destBalance = accountBalances.get(request.getDestinationAccountId());

            if (sourceBalance == null || destBalance == null) {
                response.setStatus("FAILED");
                response.setMessage("Account not found");
                response.setTransactionId("N/A");
                return response;
            }

            synchronized (this) {
                sourceBalance = accountBalances.get(request.getSourceAccountId());
                if (sourceBalance.compareTo(request.getAmount()) < 0) {
                    response.setStatus("FAILED");
                    response.setMessage("Insufficient funds");
                    response.setTransactionId("N/A");
                    processedReferences.remove(request.getTransactionReference());
                    return response;
                }

                accountBalances.put(request.getSourceAccountId(), sourceBalance.subtract(request.getAmount()));
                accountBalances.put(request.getDestinationAccountId(),
                        accountBalances.get(request.getDestinationAccountId()).add(request.getAmount()));
            }

            String transactionId = UUID.randomUUID().toString();

            TransactionRecord debitRecord = new TransactionRecord();
            debitRecord.setTransactionId(transactionId);
            debitRecord.setType("DEBIT");
            debitRecord.setAmount(request.getAmount());
            debitRecord.setCurrency(request.getCurrency());
            debitRecord.setCounterpartyAccount(request.getDestinationAccountId());
            debitRecord.setTimestamp(Instant.now().toString());
            debitRecord.setDescription(request.getDescription());

            TransactionRecord creditRecord = new TransactionRecord();
            creditRecord.setTransactionId(transactionId);
            creditRecord.setType("CREDIT");
            creditRecord.setAmount(request.getAmount());
            creditRecord.setCurrency(request.getCurrency());
            creditRecord.setCounterpartyAccount(request.getSourceAccountId());
            creditRecord.setTimestamp(Instant.now().toString());
            creditRecord.setDescription(request.getDescription());

            transactionHistory.computeIfAbsent(request.getSourceAccountId(),
                    k -> Collections.synchronizedList(new ArrayList<>())).add(debitRecord);
            transactionHistory.computeIfAbsent(request.getDestinationAccountId(),
                    k -> Collections.synchronizedList(new ArrayList<>())).add(creditRecord);

            response.setTransactionId(transactionId);
            response.setStatus("SUCCESS");
            response.setMessage("Transfer completed successfully");

            LOG.info("Transfer completed: {} from {} to {}, amount: {} {}",
                    transactionId,
                    sanitizeLogInput(request.getSourceAccountId()),
                    sanitizeLogInput(request.getDestinationAccountId()),
                    request.getAmount(),
                    request.getCurrency());

        } catch (IllegalArgumentException e) {
            response.setStatus("VALIDATION_ERROR");
            response.setMessage(e.getMessage());
            response.setTransactionId("N/A");
            LOG.warn("Validation error in transfer: {}", e.getMessage());
        } catch (Exception e) {
            response.setStatus("ERROR");
            response.setMessage("Internal processing error");
            response.setTransactionId("N/A");
            LOG.error("Error processing transfer", e);
        }

        return response;
    }

    @Override
    public BalanceResponse getBalance(BalanceRequest request) {
        BalanceResponse response = new BalanceResponse();
        response.setTimestamp(Instant.now().toString());

        try {
            validateAccountId(request.getAccountId());

            BigDecimal balance = accountBalances.get(request.getAccountId());
            if (balance == null) {
                response.setStatus("NOT_FOUND");
                response.setAccountId(request.getAccountId());
                return response;
            }

            response.setAccountId(request.getAccountId());
            response.setBalance(balance);
            response.setCurrency("USD");
            response.setStatus("SUCCESS");

            LOG.info("Balance inquiry for account: {}", sanitizeLogInput(request.getAccountId()));

        } catch (IllegalArgumentException e) {
            response.setStatus("VALIDATION_ERROR");
            LOG.warn("Validation error in balance inquiry: {}", e.getMessage());
        } catch (Exception e) {
            response.setStatus("ERROR");
            LOG.error("Error processing balance inquiry", e);
        }

        return response;
    }

    @Override
    public TransactionHistoryResponse getTransactionHistory(TransactionHistoryRequest request) {
        TransactionHistoryResponse response = new TransactionHistoryResponse();

        try {
            validateAccountId(request.getAccountId());

            int maxResults = request.getMaxResults();
            if (maxResults <= 0 || maxResults > 100) {
                maxResults = 50;
            }

            List<TransactionRecord> history = transactionHistory.get(request.getAccountId());
            if (history == null) {
                response.setAccountId(request.getAccountId());
                response.setStatus("NOT_FOUND");
                response.setTransactions(Collections.emptyList());
                return response;
            }

            List<TransactionRecord> result;
            synchronized (history) {
                int fromIndex = Math.max(0, history.size() - maxResults);
                result = new ArrayList<>(history.subList(fromIndex, history.size()));
            }

            response.setAccountId(request.getAccountId());
            response.setTransactions(result);
            response.setStatus("SUCCESS");

            LOG.info("Transaction history inquiry for account: {}", sanitizeLogInput(request.getAccountId()));

        } catch (IllegalArgumentException e) {
            response.setStatus("VALIDATION_ERROR");
            LOG.warn("Validation error in history inquiry: {}", e.getMessage());
        } catch (Exception e) {
            response.setStatus("ERROR");
            LOG.error("Error processing history inquiry", e);
        }

        return response;
    }

    private void validateTransferRequest(TransferRequest request) {
        if (request == null) {
            throw new IllegalArgumentException("Transfer request cannot be null");
        }
        validateAccountId(request.getSourceAccountId());
        validateAccountId(request.getDestinationAccountId());

        if (request.getSourceAccountId().equals(request.getDestinationAccountId())) {
            throw new IllegalArgumentException("Source and destination accounts must be different");
        }

        if (request.getAmount() == null) {
            throw new IllegalArgumentException("Amount is required");
        }
        if (request.getAmount().compareTo(MIN_TRANSFER_AMOUNT) < 0) {
            throw new IllegalArgumentException("Amount must be at least " + MIN_TRANSFER_AMOUNT);
        }
        if (request.getAmount().compareTo(MAX_TRANSFER_AMOUNT) > 0) {
            throw new IllegalArgumentException("Amount exceeds maximum allowed: " + MAX_TRANSFER_AMOUNT);
        }
        if (request.getAmount().scale() > 2) {
            throw new IllegalArgumentException("Amount cannot have more than 2 decimal places");
        }

        if (request.getCurrency() == null || !CURRENCY_PATTERN.matcher(request.getCurrency()).matches()) {
            throw new IllegalArgumentException("Invalid currency code");
        }
        if (!ALLOWED_CURRENCIES.contains(request.getCurrency())) {
            throw new IllegalArgumentException("Unsupported currency");
        }

        if (request.getTransactionReference() == null ||
                !REFERENCE_PATTERN.matcher(request.getTransactionReference()).matches()) {
            throw new IllegalArgumentException("Invalid transaction reference");
        }

        if (request.getDescription() != null && request.getDescription().length() > 256) {
            throw new IllegalArgumentException("Description too long");
        }
    }

    private void validateAccountId(String accountId) {
        if (accountId == null || accountId.isEmpty()) {
            throw new IllegalArgumentException("Account ID is required");
        }
        if (!ACCOUNT_ID_PATTERN.matcher(accountId).matches()) {
            throw new IllegalArgumentException("Invalid account ID format");
        }
    }

    private String sanitizeLogInput(String input) {
        if (input == null) return "null";
        return input.replaceAll("[\\r\\n]", "").replaceAll("[^A-Za-z0-9\\-]", "_");
    }
}

// ServerPasswordCallback.java - WS-Security Password Callback
package com.enterprise.banking.security;

import org.apache.wss4j.common.ext.WSPasswordCallback;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.security.auth.callback.Callback;
import javax.security.auth.callback.CallbackHandler;
import javax.security.auth.callback.UnsupportedCallbackException;
import java.io.IOException;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

public class ServerPasswordCallback implements CallbackHandler {

    private static final Logger LOG = LoggerFactory.getLogger(ServerPasswordCallback.class);

    // In production, retrieve from a secure vault (e.g., HashiCorp Vault, AWS Secrets Manager)
    private static final Map<String, String> KEYSTORE_PASSWORDS = new ConcurrentHashMap<>();

    static {
        // These should come from environment variables or a secure vault
        String serverKeystorePassword = System.getenv("BANKING_KEYSTORE_PASSWORD");
        if (serverKeystorePassword != null) {
            KEYSTORE_PASSWORDS.put("bankserver", serverKeystorePassword);
        }
        String clientTrustPassword = System.getenv("BANKING_CLIENT_TRUST_PASSWORD");
        if (clientTrustPassword != null) {
            KEYSTORE_PASSWORDS.put("bankclient", clientTrustPassword);
        }
    }

    @Override
    public void handle(Callback[] callbacks) throws IOException, UnsupportedCallbackException {
        for (Callback callback : callbacks) {
            if (callback instanceof WSPasswordCallback) {
                WSPasswordCallback pc = (WSPasswordCallback) callback;
                String identifier = pc.getIdentifier();

                if (identifier == null || identifier.isEmpty()) {
                    LOG.warn("Empty identifier in password callback");
                    throw new IOException("Invalid security credentials");
                }

                String password = KEYSTORE_PASSWORDS.get(identifier);
                if (password != null) {
                    pc.setPassword(password);
                    LOG.debug("Password callback handled for identifier: {}", identifier);
                } else {
                    LOG.warn("Unknown identifier in password callback: {}", identifier);
                    throw new IOException("Invalid security credentials");
                }
            } else {
                throw new UnsupportedCallbackException(callback, "Unsupported callback type");
            }
        }
    }
}

// SignatureVerificationInterceptor.java - Custom CXF Interceptor for signature verification
package com.enterprise.banking.security;

import org.apache.cxf.binding.soap.SoapMessage;
import org.apache.cxf.binding.soap.interceptor.AbstractSoapInterceptor;
import org.apache.cxf.interceptor.Fault;
import org.apache.cxf.phase.Phase;
import org.apache.cxf.ws.security.wss4j.WSS4JInInterceptor;
import org.apache.wss4j.common.ext.WSSecurityException;
import org.apache.wss4j.dom.engine.WSSecurityEngineResult;
import org.apache.wss4j.dom.handler.WSHandlerConstants;
import org.apache.wss4j.dom.handler.WSHandlerResult;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.w3c.dom.Element;

import java.security.cert.X509Certificate;
import java.util.*;

public class SignatureVerificationInterceptor extends AbstractSoapInterceptor {

    private static final Logger LOG = LoggerFactory.getLogger(SignatureVerificationInterceptor.class);

    private static final Set<String> TRUSTED_ISSUERS = Set.of(
            "CN=Enterprise Banking CA, O=Enterprise Bank, C=US",
            "CN=Enterprise Banking Intermediate CA, O=Enterprise Bank, C=US"
    );

    public SignatureVerificationInterceptor() {
        super(Phase.PRE_PROTOCOL);
        addAfter(WSS4JInInterceptor.class.getName());
    }

    @Override
    public void handleMessage(SoapMessage message) throws Fault {
        try {
            @SuppressWarnings("unchecked")
            List<WSHandlerResult> results = (List<WSHandlerResult>)
                    message.get(WSHandlerConstants.RECV_RESULTS);

            if (results == null || results.isEmpty()) {
                LOG.error("No WS-Security results found - message not signed");
                throw new Fault(new WSSecurityException(
                        WSSecurityException.ErrorCode.FAILED_CHECK,
                        "Message signature verification failed"));
            }

            boolean signatureFound = false;
            boolean timestampFound = false;

            for (WSHandlerResult result : results) {
                List<WSSecurityEngineResult> secResults = result.getResults();

                for (WSSecurityEngineResult secResult : secResults) {
                    Integer action = (Integer) secResult.get(WSSecurityEngineResult.TAG_ACTION);

                    if (action != null && (action & org.apache.wss4j.dom.WSConstants.SIGN) != 0) {
                        signatureFound = true;
                        verifySignatureCertificate(secResult);
                        extractAndLogSignedElements(secResult);
                    }

                    if (action != null && (action & org.apache.wss4j.dom.WSConstants.TS) != 0) {
                        timestampFound = true;
                        LOG.debug("Timestamp verified successfully");
                    }
                }
            }

            if (!signatureFound) {
                LOG.error("No digital signature found in the message");
                throw new Fault(new WSSecurityException(
                        WSSecurityException.ErrorCode.FAILED_CHECK,
                        "Message must be digitally signed"));
            }

            if (!timestampFound) {
                LOG.error("No timestamp found in the message");
                throw new Fault(new WSSecurityException(
                        WSSecurityException.ErrorCode.FAILED_CHECK,
                        "Message must contain a timestamp"));
            }

            LOG.info("Message signature and timestamp verified successfully");

        } catch (Fault f) {
            throw f;
        } catch (Exception e) {
            LOG.error("Error during signature verification", e);
            throw new Fault(new WSSecurityException(
                    WSSecurityException.ErrorCode.FAILED_CHECK,
                    "Signature verification error"));
        }
    }

    private void verifySignatureCertificate(WSSecurityEngineResult secResult) throws WSSecurityException {
        X509Certificate cert = (X509Certificate) secResult.get(WSSecurityEngineResult.TAG_X509_CERTIFICATE);

        if (cert == null) {
            throw new WSSecurityException(WSSecurityException.ErrorCode.FAILED_CHECK,
                    "No certificate found in signature");
        }

        // Verify certificate validity
        try {
            cert.checkValidity();
        } catch (Exception e) {
            throw new WSSecurityException(WSSecurityException.ErrorCode.FAILED_CHECK,
                    "Certificate is expired or not yet valid");
        }

        // Verify issuer is trusted
        String issuerDN = cert.getIssuerX500Principal().getName();
        boolean trustedIssuer = TRUSTED_ISSUERS.stream()
                .anyMatch(trusted -> issuerDN.contains(trusted));

        if (!trustedIssuer) {
            LOG.warn("Untrusted certificate issuer: {}", issuerDN);
            throw new WSSecurityException(WSSecurityException.ErrorCode.FAILED_CHECK,
                    "Certificate issuer is not trusted");
        }

        // Check key usage
        boolean[] keyUsage = cert.getKeyUsage();
        if (keyUsage != null && !keyUsage[0]) { // digitalSignature
            throw new WSSecurityException(WSSecurityException.ErrorCode.FAILED_CHECK,
                    "Certificate does not have digital signature key usage");
        }

        LOG.info("Certificate verified - Subject: {}, Issuer: {}, Serial: {}",
                cert.getSubjectX500Principal().getName(),
                issuerDN,
                cert.getSerialNumber());
    }

    @SuppressWarnings("unchecked")
    private void extractAndLogSignedElements(WSSecurityEngineResult secResult) {
        List<WSSecurityEngineResult> signedElements =
                (List<WSSecurityEngineResult>) secResult.get(WSSecurityEngineResult.TAG_DATA_REF_URIS);

        if (signedElements != null) {
            for (WSSecurityEngineResult signedElement : signedElements) {
                Element element = (Element) signedElement.get(WSSecurityEngineResult.TAG_TOKEN_ELEMENT);
                if (element != null) {
                    LOG.debug("Signed element: {}:{}", element.getNamespaceURI(), element.getLocalName());
                }
            }
        }
    }
}

// SOAPMessageParser.java - Secure SOAP message parser
package com.enterprise.banking.security;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;
import org.xml.sax.SAXException;

import javax.xml.XMLConstants;
import javax.xml.crypto.*;
import javax.xml.crypto.dsig.*;
import javax.xml.crypto.dsig.dom.DOMValidateContext;
import javax.xml.crypto.dsig.keyinfo.KeyInfo;
import javax.xml.crypto.dsig.keyinfo.X509Data;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.InputStream;
import java.nio.charset.StandardCharsets;
import java.security.Key;
import java.security.PublicKey;
import java.security.cert.X509Certificate;
import java.util.*;

public class SOAPMessageParser {

    private static final Logger LOG = LoggerFactory.getLogger(SOAPMessageParser.class);

    private static final String SOAP_NS = "http://schemas.xmlsoap.org/soap/envelope/";
    private static final String SOAP12_NS = "http://www.w3.org/2003/05/soap-envelope";
    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String DS_NS = "http://www.w3.org/2000/09/xmldsig#";

    private final DocumentBuilderFactory documentBuilderFactory;

    public SOAPMessageParser() {
        this.documentBuilderFactory = createSecureDocumentBuilderFactory();
    }

    private DocumentBuilderFactory createSecureDocumentBuilderFactory() {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);

        try {
            // Prevent XXE attacks
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);
        } catch (ParserConfigurationException e) {
            throw new RuntimeException("Failed to configure secure XML parser", e);
        }

        return factory;
    }

    public Document parseSOAPMessage(String soapXml) throws ParserConfigurationException, SAXException, IOException {
        if (soapXml == null || soapXml.isEmpty()) {
            throw new IllegalArgumentException("SOAP message cannot be null or empty");
        }

        // Limit message size to prevent DoS
        if (soapXml.length() > 1_000_000) {
            throw new IllegalArgumentException("SOAP message exceeds maximum allowed size");
        }

        DocumentBuilder builder = documentBuilderFactory.newDocumentBuilder();
        builder.setErrorHandler(new SecureErrorHandler());

        try (InputStream is = new ByteArrayInputStream(soapXml.getBytes(StandardCharsets.UTF_8))) {
            return builder.parse(is);
        }
    }

    public Document parseSOAPMessage(InputStream inputStream) throws ParserConfigurationException, SAXException, IOException {
        if (inputStream == null) {
            throw new IllegalArgumentException("Input stream cannot be null");
        }

        // Wrap with size-limiting stream
        InputStream limitedStream = new LimitedInputStream(inputStream, 1_000_000);

        DocumentBuilder builder = documentBuilderFactory.newDocumentBuilder();
        builder.setErrorHandler(new SecureErrorHandler());

        return builder.parse(limitedStream);
    }

    public List<SignedElementInfo> extractSignedElements(Document document) {
        List<SignedElementInfo> signedElements = new ArrayList<>();

        NodeList signatureNodes = document.getElementsByTagNameNS(DS_NS, "Signature");

        for (int i = 0; i < signatureNodes.getLength(); i++) {
            Element signatureElement = (Element) signatureNodes.item(i);
            NodeList referenceNodes = signatureElement.getElementsByTagNameNS(DS_NS, "Reference");

            for (int j = 0; j < referenceNodes.getLength(); j++) {
                Element referenceElement = (Element) referenceNodes.item(j);
                String uri = referenceElement.getAttribute("URI");

                SignedElementInfo info = new SignedElementInfo();
                info.setReferenceUri(uri);

                // Extract digest method
                NodeList digestMethodNodes = referenceElement.getElementsByTagNameNS(DS_NS, "DigestMethod");
                if (digestMethodNodes.getLength() > 0) {
                    info.setDigestMethod(((Element) digestMethodNodes.item(0)).getAttribute("Algorithm"));
                }

                // Extract digest value
                NodeList digestValueNodes = referenceElement.getElementsByTagNameNS(DS_NS, "DigestValue");
                if (digestValueNodes.getLength() > 0) {
                    info.setDigestValue(digestValueNodes.item(0).getTextContent());
                }

                // Find the referenced element
                if (uri != null && uri.startsWith("#")) {
                    String id = uri.substring(1);
                    Element referencedElement = findElementById(document, id);
                    if (referencedElement != null) {
                        info.setElementName(referencedElement.getLocalName());
                        info.setElementNamespace(referencedElement.getNamespaceURI());
                    }
                }

                // Extract transforms
                NodeList transformNodes = referenceElement.getElementsByTagNameNS(DS_NS, "Transform");
                List<String> transforms = new ArrayList<>();
                for (int k = 0; k < transformNodes.getLength(); k++) {
                    transforms.add(((Element) transformNodes.item(k)).getAttribute("Algorithm"));
                }
                info.setTransforms(transforms);

                signedElements.add(info);
                LOG.debug("Found signed element: URI={}, Element={}", uri, info.getElementName());
            }
        }

        return signedElements;
    }

    public boolean verifyXMLSignature(Document document, PublicKey publicKey) {
        try {
            NodeList signatureNodes = document.getElementsByTagNameNS(DS_NS, "Signature");

            if (signatureNodes.getLength() == 0) {
                LOG.warn("No XML signature found in document");
                return false;
            }

            for (int i = 0; i < signatureNodes.getLength(); i++) {
                Element signatureElement = (Element) signatureNodes.item(i);

                DOMValidateContext validateContext = new DOMValidateContext(publicKey, signatureElement);

                // Register ID attributes for reference resolution
                registerIdAttributes(document, validateContext);

                XMLSignatureFactory factory = XMLSignatureFactory.getInstance("DOM");
                XMLSignature signature = factory.unmarshalXMLSignature(validateContext);

                boolean coreValid = signature.validate(validateContext);

                if (!coreValid) {
                    LOG.error("XML Signature core validation failed");

                    // Log which references failed
                    boolean signatureValueValid = signature.getSignatureValue().validate(validateContext);
                    LOG.error("Signature value validation: {}", signatureValueValid);

                    @SuppressWarnings("unchecked")
                    List<Reference> references = signature.getSignedInfo().getReferences();
                    for (Reference ref : references) {
                        boolean refValid = ref.validate(validateContext);
                        LOG.error("Reference URI={} validation: {}", ref.getURI(), refValid);
                    }

                    return false;
                }

                // Verify the signing certificate if present in KeyInfo
                verifyCertificateFromKeyInfo(signature.getKeyInfo());

                LOG.info("XML Signature {} verified successfully", i);
            }

            return true;

        } catch (XMLSignatureException | MarshalException e) {
            LOG.error("Error verifying XML signature", e);
            return false;
        }
    }

    public boolean verifyXMLSignatureWithKeySelector(Document document) {
        try {
            NodeList signatureNodes = document.getElementsByTagNameNS(DS_NS, "Signature");

            if (signatureNodes.getLength() == 0) {
                LOG.warn("No XML signature found in document");
                return false;
            }

            Element signatureElement = (Element) signatureNodes.item(0);

            DOMValidateContext validateContext = new DOMValidateContext(
                    new X509KeySelector(), signatureElement);

            registerIdAttributes(document, validateContext);

            XMLSignatureFactory factory = XMLSignatureFactory.getInstance("DOM");
            XMLSignature signature = factory.unmarshalXMLSignature(validateContext);

            return signature.validate(validateContext);

        } catch (Exception e) {
            LOG.error("Error verifying XML signature with key selector", e);
            return false;
        }
    }

    private Element findElementById(Document document, String id) {
        // Search by wsu:Id
        NodeList allElements = document.getElementsByTagName("*");
        for (int i = 0; i < allElements.getLength(); i++) {
            Element element = (Element) allElements.item(i);
            if (id.equals(element.getAttributeNS(
                    "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd", "Id"))) {
                return element;
            }
            if (id.equals(element.getAttribute("Id"))) {
                return element;
            }
            if (id.equals(element.getAttribute("id"))) {
                return element;
            }
        }
        return null;
    }

    private void registerIdAttributes(Document document, DOMValidateContext validateContext) {
        NodeList allElements = document.getElementsByTagName("*");
        String wsuNs = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";

        for (int i = 0; i < allElements.getLength(); i++) {
            Element element = (Element) allElements.item(i);
            if (element.hasAttributeNS(wsuNs, "Id")) {
                validateContext.setIdAttributeNS(element, wsuNs, "Id");
            }
            if (element.hasAttribute("Id")) {
                validateContext.setIdAttributeNS(element, null, "Id");
            }
        }
    }

    private void verifyCertificateFromKeyInfo(KeyInfo keyInfo) {
        if (keyInfo == null) return;

        @SuppressWarnings("unchecked")
        List<XMLStructure> keyInfoContent = keyInfo.getContent();
        for (XMLStructure structure : keyInfoContent) {
            if (structure instanceof X509Data) {
                @SuppressWarnings("unchecked")
                List<Object> x509Content = ((X509Data) structure).getContent();
                for (Object item : x509Content) {
                    if (item instanceof X509Certificate) {
                        X509Certificate cert = (X509Certificate) item;
                        try {
                            cert.checkValidity();
                            LOG.info("Signing certificate is valid. Subject: {}",
                                    cert.getSubjectX500Principal().getName());
                        } catch (Exception e) {
                            LOG.warn("Signing certificate validation issue: {}", e.getMessage());
                        }
                    }
                }
            }
        }
    }

    // Inner class for X509 key selection
    private static class X509KeySelector extends KeySelector {
        @Override
        public KeySelectorResult select(KeyInfo keyInfo, Purpose purpose,
                                         AlgorithmMethod method, XMLCryptoContext context)
                throws KeySelectorException {

            if (keyInfo == null) {
                throw new KeySelectorException("No KeyInfo found");
            }

            @SuppressWarnings("unchecked")
            List<XMLStructure> keyInfoContent = keyInfo.getContent();
            for (XMLStructure structure : keyInfoContent) {
                if (structure instanceof X509Data) {
                    @SuppressWarnings("unchecked")
                    List<Object> x509Content = ((X509Data) structure).getContent();
                    for (Object item : x509Content) {
                        if (item instanceof X509Certificate) {
                            X509Certificate cert = (X509Certificate) item;
                            try {
                                cert.checkValidity();
                            } catch (Exception e) {
                                throw new KeySelectorException("Certificate is not valid", e);
                            }
                            final PublicKey publicKey = cert.getPublicKey();
                            return () -> publicKey;
                        }
                    }
                }
            }

            throw new KeySelectorException("No suitable key found in KeyInfo");
        }
    }

    // Signed element info DTO
    public static class SignedElementInfo {
        private String referenceUri;
        private String elementName;
        private String elementNamespace;
        private String digestMethod;
        private String digestValue;
        private List<String> transforms;

        public String getReferenceUri() { return referenceUri; }
        public void setReferenceUri(String referenceUri) { this.referenceUri = referenceUri; }
        public String getElementName() { return elementName; }
        public void setElementName(String elementName) { this.elementName = elementName; }
        public String getElementNamespace() { return elementNamespace; }
        public void setElementNamespace(String elementNamespace) { this.elementNamespace = elementNamespace; }
        public String getDigestMethod() { return digestMethod; }
        public void setDigestMethod(String digestMethod) { this.digestMethod = digestMethod; }
        public String getDigestValue() { return digestValue; }
        public void setDigestValue(String digestValue) { this.digestValue = digestValue; }
        public List<String> getTransforms() { return transforms; }
        public void setTransforms(List<String> transforms) { this.transforms = transforms; }

        @Override
        public String toString() {
            return "SignedElementInfo{uri='" + referenceUri + "', element='" + elementName +
                    "', namespace='" + elementNamespace + "', digest='" + digestMethod + "'}";
        }
    }

    // Secure error handler to prevent information leakage
    private static class SecureErrorHandler implements org.xml.sax.ErrorHandler {
        private static final Logger LOG = LoggerFactory.getLogger(SecureErrorHandler.class);

        @Override
        public void warning(org.xml.sax.SAXParseException e) throws SAXException {
            LOG.warn("XML parsing warning at line {}", e.getLineNumber());
        }

        @Override
        public void error(org.xml.sax.SAXParseException e) throws SAXException {
            LOG.error("XML parsing error at line {}", e.getLineNumber());
            throw new SAXException("XML parsing error");
        }

        @Override
        public void fatalError(org.xml.sax.SAXParseException e) throws SAXException {
            LOG.error("XML parsing fatal error at line {}", e.getLineNumber());
            throw new SAXException("XML parsing fatal error");
        }
    }

    // Input stream wrapper to limit size
    private static class LimitedInputStream extends InputStream {
        private final InputStream wrapped;
        private final long maxSize;
        private long bytesRead = 0;

        public LimitedInputStream(InputStream wrapped, long maxSize) {
            this.wrapped = wrapped;
            this.maxSize = maxSize;
        }

        @Override
        public int read() throws IOException {
            if (bytesRead >= maxSize) {
                throw new IOException("Input exceeds maximum allowed size");
            }
            int result = wrapped.read();
            if (result != -1) {
                bytesRead++;
            }
            return result;
        }

        @Override
        public int read(byte[] b, int off, int len) throws IOException {
            if (bytesRead >= maxSize) {
                throw new IOException("Input exceeds maximum allowed size");
            }
            int allowedLen = (int) Math.min(len, maxSize - bytesRead);
            int result = wrapped.read(b, off, allowedLen);
            if (result > 0) {
                bytesRead += result;
            }
            return result;
        }

        @Override
        public void close() throws IOException {
            wrapped.close();
        }
    }
}

// ReplayAttackPreventionInterceptor.java - Prevent replay attacks
package com.enterprise.banking.security;

import org.apache.cxf.binding.soap.SoapMessage;
import org.apache.cxf.binding.soap.interceptor.AbstractSoapInterceptor;
import org.apache.cxf.interceptor.Fault;
import org.apache.cxf.phase.Phase;
import org.apache.wss4j.common.ext.WSSecurityException;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

public class ReplayAttackPreventionInterceptor extends AbstractSoapInterceptor {

    private static final Logger LOG = LoggerFactory.getLogger(ReplayAttackPreventionInterceptor.class);
    private static final long NONCE_CACHE_TTL_MINUTES = 10;

    private final ConcurrentHashMap<String, Long> nonceCache = new ConcurrentHashMap<>();
    private final ScheduledExecutorService cleanupExecutor;

    public ReplayAttackPreventionInterceptor() {
        super(Phase.PRE_PROTOCOL);
        addAfter(SignatureVerificationInterceptor.class.getName());

        cleanupExecutor = Executors.newSingleThreadScheduledExecutor(r -> {
            Thread t = new Thread(r, "nonce-cache-cleanup");
            t.setDaemon(true);
            return t;
        });

        cleanupExecutor.scheduleAtFixedRate(this::cleanupExpiredNonces,
                NONCE_CACHE_TTL_MINUTES, NONCE_CACHE_TTL_MINUTES, TimeUnit.MINUTES);
    }

    @Override
    public void handleMessage(SoapMessage message) throws Fault {
        String messageId = (String) message.get("org.apache.cxf.message.Message.ID");

        if (messageId != null) {
            Long previousTimestamp = nonceCache.putIfAbsent(messageId, System.currentTimeMillis());
            if (previousTimestamp != null) {
                LOG.warn("Potential replay attack detected. Message ID: {}", messageId);
                throw new Fault(new WSSecurityException(
                        WSSecurityException.ErrorCode.FAILED_CHECK,
                        "Replay attack detected"));
            }
        }
    }

    private void cleanupExpiredNonces() {
        long cutoff = System.currentTimeMillis() - TimeUnit.MINUTES.toMillis(NONCE_CACHE_TTL_MINUTES);
        nonceCache.entrySet().removeIf(entry -> entry.getValue() < cutoff);
        LOG.debug("Nonce cache cleanup completed. Remaining entries: {}", nonceCache.size());
    }

    public void shutdown() {
        cleanupExecutor.shutdown();
    }
}

// BankingServiceConfig.java - CXF Configuration
package com.enterprise.banking.config;

import com.enterprise.banking.security.ReplayAttackPreventionInterceptor;
import com.enterprise.banking.security.ServerPasswordCallback;
import com.enterprise.banking.security.SignatureVerificationInterceptor;
import com.enterprise.banking.service.BankingServiceImpl;
import org.apache.cxf.Bus;
import org.apache.cxf.bus.spring.SpringBus;
import org.apache.cxf.jaxws.EndpointImpl;
import org.apache.cxf.ws.security.wss4j.WSS4JInInterceptor;
import org.apache.cxf.ws.security.wss4j.WSS4JOutInterceptor;
import org.apache.wss4j.dom.handler.WSHandlerConstants;

import javax.xml.ws.Endpoint;
import java.util.HashMap;
import java.util.Map;

public class BankingServiceConfig {

    public Bus cxfBus() {
        return new SpringBus();
    }

    public Endpoint bankingServiceEndpoint() {
        EndpointImpl endpoint = new EndpointImpl(cxfBus(), new BankingServiceImpl());
        endpoint.publish("/BankingService");

        // Add WS-Security interceptors
        endpoint.getInInterceptors().add(createWSS4JInInterceptor());
        endpoint.getOutInterceptors().add(createWSS4JOutInterceptor());

        // Add custom security interceptors
        endpoint.getInInterceptors().add(new SignatureVerificationInterceptor());
        endpoint.getInInterceptors().add(new ReplayAttackPreventionInterceptor());

        // Security properties
        Map<String, Object> properties = new HashMap<>();
        properties.put("ws-security.signature.properties", "server-crypto.properties");
        properties.put("ws-security.encryption.properties", "server-crypto.properties");
        properties.put("ws-security.callback-handler", new ServerPasswordCallback());
        properties.put("ws-security.timestamp.timeToLive", "300");
        properties.put("ws-security.timestamp.futureTimeToLive", "60");
        properties.put("ws-security.is-bsp-compliant", "true");
        endpoint.setProperties(properties);

        return endpoint;
    }

    private WSS4JInInterceptor createWSS4JInInterceptor() {
        Map<String, Object> inProps = new HashMap<>();

        // Require Timestamp, Signature, and Encryption
        inProps.put(WSHandlerConstants.ACTION,
                WSHandlerConstants.TIMESTAMP + " " +
                        WSHandlerConstants.SIGNATURE + " " +
                        WSHandlerConstants.ENCRYPT);

        // Signature configuration
        inProps.put(WSHandlerConstants.SIG_PROP_FILE, "server-crypto.properties");
        inProps.put(WSHandlerConstants.SIG_ALGO, "http://www.w3.org/2001/04/xmldsig-more#rsa-sha256");
        inProps.put(WSHandlerConstants.SIG_DIGEST_ALGO, "http://www.w3.org/2001/04/xmlenc#sha256");

        // Decryption configuration
        inProps.put(WSHandlerConstants.DEC_PROP_FILE, "server-crypto.properties");
        inProps.put(WSHandlerConstants.PW_CALLBACK_CLASS,
                ServerPasswordCallback.class.getName());

        // Require signed body and timestamp
        inProps.put(WSHandlerConstants.SIG_KEY_ID, "DirectReference");

        // Enforce BSP compliance
        inProps.put(WSHandlerConstants.IS_BSP_COMPLIANT, "true");

        return new WSS4JInInterceptor(inProps);
    }

    private WSS4JOutInterceptor createWSS4JOutInterceptor() {
        Map<String, Object> outProps = new HashMap<>();

        // Sign and encrypt responses
        outProps.put(WSHandlerConstants.ACTION,
                WSHandlerConstants.TIMESTAMP + " " +
                        WSHandlerConstants.SIGNATURE + " " +
                        WSHandlerConstants.ENCRYPT);

        // Signature configuration
        outProps.put(WSHandlerConstants.USER, "bankserver");
        outProps.put(WSHandlerConstants.SIG_PROP_FILE, "server-crypto.properties");
        outProps.put(WSHandlerConstants.SIG_ALGO, "http://www.w3.org/2001/04/xmldsig-more#rsa-sha256");
        outProps.put(WSHandlerConstants.SIG_DIGEST_ALGO, "http://www.w3.org/2001/04/xmlenc#sha256");
        outProps.put(WSHandlerConstants.SIGNATURE_PARTS,
                "{Element}{http://schemas.xmlsoap.org/soap/envelope/}Body;" +
                        "{Element}{http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd}Timestamp");

        // Encryption configuration
        outProps.put(WSHandlerConstants.ENC_PROP_FILE, "server-crypto.properties");
        outProps.put(WSHandlerConstants.ENCRYPTION_USER, "useReqSigCert");
        outProps.put(WSHandlerConstants.ENC_KEY_TRANSPORT, "http://www.w3.org/2001/04/xmlenc#rsa-oaep-mgf1p");
        outProps.put(WSHandlerConstants.ENC_SYM_ALGO, "http://www.w3.org/2001/04/xmlenc#aes256-cbc");
        outProps.put(WSHandlerConstants.ENCRYPTION_PARTS,
                "{Content}{http://schemas.xmlsoap.org/soap/envelope/}Body");

        outProps.put(WSHandlerConstants.PW_CALLBACK_CLASS,
                ServerPasswordCallback.class.getName());

        return new WSS4JOutInterceptor(outProps);
    }
}

// AuditInterceptor.java - Audit logging interceptor
package com.enterprise.banking.security;

import org.apache.cxf.binding.soap.SoapMessage;
import org.apache.cxf.binding.soap.interceptor.AbstractSoapInterceptor;
import org.apache.cxf.interceptor.Fault;
import org.apache.cxf.phase.Phase;
import org.apache.wss4j.dom.engine.WSSecurityEngineResult;
import org.apache.wss4j.dom.handler.WSHandlerConstants;
import org.apache.wss4j.dom.handler.WSHandlerResult;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.security.cert.X509Certificate;
import java.time.Instant;
import java.util.List;

public class AuditInterceptor extends AbstractSoapInterceptor {

    private static final Logger AUDIT_LOG = LoggerFactory.getLogger("AUDIT");

    public AuditInterceptor() {
        super(Phase.POST_PROTOCOL);
    }

    @Override
    public void handleMessage(SoapMessage message) throws Fault {
        try {
            String operation = extractOperation(message);
            String clientIdentity = extractClientIdentity(message);
            String remoteAddress = extractRemoteAddress(message);

            AUDIT_LOG.info("BANKING_API_ACCESS | timestamp={} | operation={} | client={} | remoteAddr={} | status=PROCESSING",
                    Instant.now(),
                    sanitize(operation),
                    sanitize(clientIdentity),
                    sanitize(remoteAddress));

        } catch (Exception e) {
            AUDIT_LOG.warn("Failed to create audit log entry", e);
        }
    }

    @SuppressWarnings("unchecked")
    private String extractClientIdentity(SoapMessage message) {
        try {
            List<WSHandlerResult> results = (List<WSHandlerResult>)
                    message.get(WSHandlerConstants.RECV_RESULTS);

            if (results != null) {
                for (WSHandlerResult result : results) {
                    for (WSSecurityEngineResult secResult : result.getResults()) {
                        X509Certificate cert = (X509Certificate)
                                secResult.get(WSSecurityEngineResult.TAG_X509_CERTIFICATE);
                        if (cert != null) {
                            return cert.getSubjectX500Principal().getName();
                        }
                    }
                }
            }
        } catch (Exception e) {
            // Ignore
        }
        return "UNKNOWN";
    }

    private String extractOperation(SoapMessage message) {
        try {
            if (message.getExchange() != null &&
                    message.getExchange().getBindingOperationInfo() != null) {
                return message.getExchange().getBindingOperationInfo().getName().getLocalPart();
            }
        } catch (Exception e) {
            // Ignore
        }
        return "UNKNOWN";
    }

    private String extractRemoteAddress(SoapMessage message) {
        try {
            javax.servlet.http.HttpServletRequest request =
                    (javax.servlet.http.HttpServletRequest) message.get("HTTP.REQUEST");
            if (request != null) {
                return request.getRemoteAddr();
            }
        } catch (Exception e) {
            // Ignore
        }
        return "UNKNOWN";
    }

    private String sanitize(String input) {
        if (input == null) return "null";
        return input.replaceAll("[\\r\\n]", "").replaceAll("[^A-Za-z0-9=,. \\-@]", "_");
    }
}

// BankingServicePublisher.java - Main entry point
package com.enterprise.banking;

import com.enterprise.banking.config.BankingServiceConfig;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.xml.ws.Endpoint;

public class BankingServicePublisher {

    private static final Logger LOG = LoggerFactory.getLogger(BankingServicePublisher.class);

    public static void main(String[] args) {
        // Validate required environment variables
        validateEnvironment();

        BankingServiceConfig config = new BankingServiceConfig();
        Endpoint endpoint = config.bankingServiceEndpoint();

        LOG.info("Banking SOAP Web Service started successfully");
        LOG.info("WSDL available at: https://localhost:8443/services/BankingService?wsdl");

        // Add shutdown hook
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            LOG.info("Shutting down Banking Service...");
            if (endpoint.isPublished()) {
                endpoint.stop();
            }
            LOG.info("Banking Service stopped");
        }));
    }

    private static void validateEnvironment() {
        String[] requiredEnvVars = {
                "BANKING_KEYSTORE_PASSWORD",
                "BANKING_KEYSTORE_PATH",
                "BANKING_TRUSTSTORE_PATH"
        };

        for (String envVar : requiredEnvVars) {
            if (System.getenv(envVar) == null || System.getenv(envVar).isEmpty()) {
                LOG.error("Required environment variable not set: {}", envVar);
                System.exit(1);
            }
        }
    }
}